import xml.etree.ElementTree as ET

def read_and_validate_xml(file_object):
    try:
        tree = ET.parse(file_object)
        root = tree.getroot()
        return True, root
    except ET.ParseError as error:
        return False, str(error)

# Example usage:
if __name__ == "__main__":
    with open('example.xml', 'rb') as f:
        is_valid, result = read_and_validate_xml(f)
        if is_valid:
            print("XML is valid.")
        else:
            print("Invalid XML:", result)